	private void ensureLayout() throws IOException {
		for (byte slot = 0; slot < 2; slot++) {
			Files.createDirectories(slotDirectory(slot));
			touch(indexPath(slot));
		}
	}

	private void deleteDirectoryContents() throws IOException {
		if (!Files.isDirectory(directory)) {
			return;
		}
		try (var paths = Files.walk(directory)) {
			try {
				paths.filter(path -> !path.equals(directory))
						.sorted(Comparator.reverseOrder())
						.forEach(path -> {
							try {
								Files.deleteIfExists(path);
							} catch (IOException e) {
								throw new DeletePathException(e);
							}
						});
			} catch (DeletePathException e) {
				throw e.cause;
			}
		}
	}

	private void touch(Path path) throws IOException {
		Files.createDirectories(path.getParent());
		if (!Files.exists(path)) {
			Files.createFile(path);
		}
	}

	private Path metadataPath() {
		return directory.resolve("metadata.bin");
	}

	private Path indexPath(byte slot) {
		return slotDirectory(slot).resolve("index.bin");
	}

	private Path sketchesPartPath(byte slot, byte fileKind, long chunkStart) {
		long partIndex = chunkStart / sketchFileChunks.chunkBytes(fileKind);
		return slotDirectory(slot).resolve(sketchesBaseName(fileKind) + ".part" + (partIndex + 1L) + ".sketches");
	}

	private static String sketchesBaseName(byte fileKind) {
		return switch (fileKind) {
		case FILE_KIND_GLOBAL -> "global";
		case FILE_KIND_SINGLES -> "singles";
		case FILE_KIND_PAIRS -> "pairs";
		default -> throw new IllegalArgumentException("Unknown sketch file kind: " + fileKind);
		};
	}

	private Path slotDirectory(byte slot) {
		return directory.resolve(slot == 0 ? "a" : "b");
	}

	private static byte[] readWholeFile(Path path) throws IOException {
		long length = Files.size(path);
		if (length > Integer.MAX_VALUE) {
			throw new IOException("File too large to read into memory: " + path + " (" + length + " bytes)");
		}
		if (length == 0L) {
			return new byte[0];
		}
		try (FileChannel channel = FileChannel.open(path, StandardOpenOption.READ);
				Arena arena = Arena.ofConfined()) {
			MemorySegment segment = channel.map(FileChannel.MapMode.READ_ONLY, 0L, length, arena);
			return segment.toArray(ValueLayout.JAVA_BYTE);
		}
	}

	private static void writeAtomicallyMapped(Path target, byte[] payload) throws IOException {
		Files.createDirectories(target.getParent());
		Path tmp = target.resolveSibling(target.getFileName().toString() + ".tmp");
		try (FileChannel channel = FileChannel.open(tmp, StandardOpenOption.CREATE,
				StandardOpenOption.TRUNCATE_EXISTING,
				StandardOpenOption.READ, StandardOpenOption.WRITE)) {
			ensureChannelSize(channel, payload.length);
			if (payload.length > 0) {
				try (Arena arena = Arena.ofConfined()) {
					MemorySegment segment = channel.map(FileChannel.MapMode.READ_WRITE, 0L, payload.length, arena);
					MemorySegment.copy(MemorySegment.ofArray(payload), 0L, segment, 0L, payload.length);
					segment.force();
				}
			}
		}
		try {
			Files.move(tmp, target, StandardCopyOption.REPLACE_EXISTING, StandardCopyOption.ATOMIC_MOVE);
		} catch (IOException e) {
			Files.move(tmp, target, StandardCopyOption.REPLACE_EXISTING);
		}
	}

	private static void ensureChannelSize(FileChannel channel, long size) throws IOException {
		if (size <= 0L) {
			channel.truncate(0L);
			return;
		}
		long current = channel.size();
		if (current < size) {
			channel.write(ByteBuffer.wrap(FILE_GROWTH_MARKER), size - 1L);
		}
		if (current > size) {
			channel.truncate(size);
		}
	}

	private static void writeIntBigEndian(MemorySegment segment, long offset, int value) {
		segment.set(ValueLayout.JAVA_BYTE, offset, (byte) (value >>> 24));
		segment.set(ValueLayout.JAVA_BYTE, offset + 1L, (byte) (value >>> 16));
		segment.set(ValueLayout.JAVA_BYTE, offset + 2L, (byte) (value >>> 8));
		segment.set(ValueLayout.JAVA_BYTE, offset + 3L, (byte) value);
	}

	private static int readIntBigEndian(MemorySegment segment, long offset) {
		return ((segment.get(ValueLayout.JAVA_BYTE, offset) & 0xff) << 24)
				| ((segment.get(ValueLayout.JAVA_BYTE, offset + 1L) & 0xff) << 16)
				| ((segment.get(ValueLayout.JAVA_BYTE, offset + 2L) & 0xff) << 8)
				| (segment.get(ValueLayout.JAVA_BYTE, offset + 3L) & 0xff);
	}

	@FunctionalInterface
	interface SegmentReader<T> {
		T read(MemorySegment payload) throws IOException;
	}

	record FramedPayloadAllocation(Ref ref, MemorySegment payload) {
	}

	private record MappedSketchSlice(MemorySegment segment) {
	}

	private record MappedSketchChunkKey(byte slot, byte fileKind, long chunkStart) {

		@Override
		public boolean equals(Object other) {
			if (this == other) {
				return true;
			}
			if (!(other instanceof MappedSketchChunkKey)) {
				return false;
			}
			MappedSketchChunkKey that = (MappedSketchChunkKey) other;
			return slot == that.slot && fileKind == that.fileKind && chunkStart == that.chunkStart;
		}

		@Override
		public int hashCode() {
			int result = slot;
			result = 31 * result + fileKind;
			result = 31 * result + Long.hashCode(chunkStart);
			return result;
		}
	}

	private static final class MappedSketchChunk implements AutoCloseable {
		private final Path file;
		private final long length;
		private Arena arena;
		private MemorySegment segment;

		private MappedSketchChunk(Path file, long length) {
			this.file = file;
			this.length = length;
		}

		private void map(boolean create) throws IOException {
			if (!create && !Files.isRegularFile(file)) {
				throw new NoSuchFileException(file.toString());
			}
			Files.createDirectories(file.getParent());
			try (FileChannel channel = create
					? FileChannel.open(file, StandardOpenOption.CREATE, StandardOpenOption.READ,
							StandardOpenOption.WRITE)
					: FileChannel.open(file, StandardOpenOption.READ, StandardOpenOption.WRITE)) {
				if (create) {
					ensureChannelSize(channel, length);
				} else if (channel.size() < length) {
					throw new IOException("Persisted sketch part is smaller than configured chunk: " + file
							+ " size=" + channel.size() + " chunk=" + length);
				}
				Arena mappedArena = Arena.ofShared();
				try {
					MemorySegment mappedSegment = channel.map(FileChannel.MapMode.READ_WRITE, 0L, length,
							mappedArena);
					arena = mappedArena;
					segment = mappedSegment;
				} catch (IOException | RuntimeException e) {
					mappedArena.close();
					throw e;
				}
			}
		}

		@Override
		public void close() {
			if (arena != null) {
				arena.close();
				arena = null;
				segment = null;
			}
		}
	}

	private static final class DeletePathException extends RuntimeException {
		private static final long serialVersionUID = 1L;

		private final IOException cause;

		private DeletePathException(IOException cause) {
			super(cause);
			this.cause = cause;
		}
	}

	static final class SketchFileChunks {
		private final long globalChunkBytes;
		private final long singlesChunkBytes;
		private final long pairsChunkBytes;

		private SketchFileChunks(long globalChunkBytes, long singlesChunkBytes, long pairsChunkBytes) {
			this.globalChunkBytes = Math.max(1L, globalChunkBytes);
			this.singlesChunkBytes = Math.max(1L, singlesChunkBytes);
			this.pairsChunkBytes = Math.max(1L, pairsChunkBytes);
		}

		static SketchFileChunks of(long globalChunkBytes, long singlesChunkBytes, long pairsChunkBytes) {
			return new SketchFileChunks(globalChunkBytes, singlesChunkBytes, pairsChunkBytes);
		}

		static SketchFileChunks uniform(long chunkBytes) {
			return new SketchFileChunks(chunkBytes, chunkBytes, chunkBytes);
		}

		long chunkBytes(byte fileKind) {
			return switch (fileKind) {
			case FILE_KIND_GLOBAL -> globalChunkBytes;
			case FILE_KIND_SINGLES -> singlesChunkBytes;
			case FILE_KIND_PAIRS -> pairsChunkBytes;
			default -> throw new IllegalArgumentException("Unknown sketch file kind: " + fileKind);
			};
		}
	}

